let cache;
try { cache = JSON.parse($input.item.json.stdout || '{}'); } catch { return []; }
const c = cache.cwv || {};
const poor = c.pagesPoor || 0;
const worst = [];
if (c.worstLcpMs && c.worstLcpMs > 2500) worst.push(`LCP ${c.worstLcpMs}ms (>2500)`);
if (c.worstInpMs && c.worstInpMs > 200)  worst.push(`INP ${c.worstInpMs}ms (>200)`);
if (c.worstCls  && c.worstCls  > 0.1)   worst.push(`CLS ${c.worstCls.toFixed(3)} (>0.1)`);
if (poor === 0 && worst.length === 0) return [];
return [{ json: {
  priority: 'P1',
  source: 'cwv-watch',
  message: `Core Web Vitals breach:\n• ${poor} page(s) in Poor bucket\n• ${worst.join(' · ') || 'thresholds within range'}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/seo'
} }];
